const url = $.input.spreadsheetUrl;
const sheetName = $.input.sheetName || 'Sheet1';
const campaignCtx = $.input.campaignContext;
const subject = $.input.campaignSubject;
const sender = $.input.senderName || 'Your Name';

const sampleRecipients = [
  { name: 'Sample Recipient', email: 'sample@example.com', company: 'Example Corp', role: 'CTO', notes: 'Interested in AI automation' }
];

return { recipients: sampleRecipients, totalCount: sampleRecipients.length, campaignContext: campaignCtx, subject, sender, spreadsheetUrl: url, sheetName };

const d = $.steps.prepareRecipients.output;

let recipientData = '';
d.recipients.forEach((r, i) => {
  recipientData += 'RECIPIENT ' + (i + 1) + ':\n';
  recipientData += '  Name: ' + (r.name || r.Name || '') + '\n';
  recipientData += '  Email: ' + (r.email || r.Email || '') + '\n';
  recipientData += '  Company: ' + (r.company || r.Company || '') + '\n';
  recipientData += '  Role: ' + (r.role || r.Role || '') + '\n';
  recipientData += '  Notes: ' + (r.notes || r.Notes || '') + '\n\n';
});

let prompt = 'You are an expert email copywriter. Create personalized outreach emails for each recipient below.\n\n';
prompt += 'CAMPAIGN CONTEXT: ' + d.campaignContext + '\n';
prompt += 'SUBJECT TEMPLATE: ' + d.subject + '\n';
prompt += 'SENDER NAME: ' + d.sender + '\n\n';
prompt += 'RECIPIENTS:\n' + recipientData + '\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Write a unique, personalized email for each recipient\n';
prompt += '- Reference their company, role, or notes where relevant\n';
prompt += '- Keep each email 100-200 words, professional but warm\n';
prompt += '- Include a clear CTA\n';
prompt += '- Personalize the subject line using the template\n';
prompt += '- Use HTML formatting with <p> tags\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "emails": [\n';
prompt += '    {\n';
prompt += '      "recipientIndex": 1,\n';
prompt += '      "to": "email@example.com",\n';
prompt += '      "name": "recipient name",\n';
prompt += '      "subject": "personalized subject",\n';
prompt += '      "body": "<p>personalized HTML email body</p>",\n';
prompt += '      "personalizationNotes": "what was personalized"\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "totalEmails": 0\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiPersonalize.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { emails: [], totalEmails: 0, error: raw }; }

const ai = $.steps.parseAI.output;
const emails = ai.emails || [];
const iterations = $.steps.sendEmails.response.iterations || [];

let sentCount = 0;
let failedCount = 0;
iterations.forEach(iter => {
  if (iter.sendOne && !iter.sendOne.error) sentCount++;
  else failedCount++;
});

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Email Campaign Complete' } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Total Recipients:*\n' + emails.length },
  { type: 'mrkdwn', text: '*Successfully Sent:*\n' + sentCount }
] });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Failed:*\n' + failedCount },
  { type: 'mrkdwn', text: '*Campaign:*\n' + ($.input.campaignContext || '').slice(0, 100) }
] });
blocks.push({ type: 'divider' });

let recipientList = '';
emails.slice(0, 10).forEach((e, i) => {
  const status = (iterations[i] && iterations[i].sendOne && !iterations[i].sendOne.error) ? ':white_check_mark:' : ':x:';
  recipientList += status + ' ' + e.name + ' (' + e.to + ')\n';
});
if (emails.length > 10) recipientList += '... and ' + (emails.length - 10) + ' more';

blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Recipients:*\n' + recipientList.slice(0, 1800) } });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Claude AI + Gmail + Google Sheets' }] });

const fallback = 'Email campaign sent: ' + sentCount + '/' + emails.length + ' delivered';
return { blocks, fallback };
